 30 | class AgentTurn {
 31 |   private onStreamCreateFns: Array<(stream: MessageStream<null>) => void> = [];
 32 |   private onToolUseFns: Array<
 33 |     (
 34 |       toolUseId: string,
 35 |       toolName: string,
 36 |       toolInput: Record<string, any>,
 37 |       completed: boolean,
 38 |     ) => void
 39 |   > = [];
 40 |   onStreamCreate(fn: (stream: MessageStream<null>) => void) {
 41 |     this.onStreamCreateFns.push(fn);
 42 |   }
 43 |   onToolUse(
 44 |     fn: (
 45 |       toolUseId: string,
 46 |       toolName: string,
 47 |       toolInput: Record<string, any>,
 48 |       completed: boolean,
 49 |     ) => void,
 50 |   ) {
 51 |     this.onToolUseFns.push(fn);
 52 |   }
 53 |   async executeSingleIteration(): Promise<IterationResult> {
 54 |     const messages = messagesAtom.get();
 55 |     const stream = client.messages.stream({
 56 |       model: MODEL,
 57 |       max_tokens: 2048,
 58 |       system: systemPrompt,
 59 |       messages,
 60 |       tools: toolDefinitions,
 61 |     });
 62 |     this.onStreamCreateFns.forEach((fn) => fn(stream));
 63 |     let hasToolUse = false;
 64 |     const completedToolUses: Array<{ id: string; name: string; input: Record<string, any> }> = [];
 65 |     stream.on('contentBlock', (content) => {
 66 |       if (content.type === 'tool_use') {
 67 |         hasToolUse = true;
 68 |         completedToolUses.push({
 69 |           id: content.id,
 70 |           name: content.name,
 71 |           input: content.input as Record<string, any>,
 72 |         });
 73 |       }
 74 |     });
 75 |     // 等待流结束，获取完整消息
 76 |     const finalMessage = await stream.finalMessage();
 77 |     messagesAtom.set([...messages, finalMessage]);
 78 |     // 执行工具并收集结果
 79 |     if (completedToolUses.length > 0) {
 80 |       const toolResults: Anthropic.ToolResultBlockParam[] = [];
 81 |       for (const tool of completedToolUses) {
 82 |         let result: string;
 83 |         try {
 84 |           this.onToolUseFns.forEach((fn) => fn(tool.id, tool.name, tool.input, false));
 85 |           result = await executeTool(tool.name, tool.input);
 86 |         } catch (error) {
 87 |           const message =
 88 |             error instanceof Error ? `${error.name}: ${error.message}` : String(error);
 89 |           result = `工具 ${tool.name} 执行异常：\n${message}`;
 90 |         }
 91 |         toolResults.push({
 92 |           type: 'tool_result',
 93 |           tool_use_id: tool.id,
 94 |           content: result,
 95 |         });
 96 |         this.onToolUseFns.forEach((fn) => fn(tool.id, tool.name, tool.input, true));
 97 |       }
 98 |       messagesAtom.set([
 99 |         ...messagesAtom.get(),
100 |         {
101 |           role: 'user',
102 |           content: toolResults,
103 |         },
104 |       ]);
105 |     }
106 | 
107 |     return { hasToolUse, finalMessage };
108 |   }
109 |   async run(userInput: string, onIteration?: (result: IterationResult) => void) {
110 |     messagesAtom.set([...messagesAtom.get(), { role: 'user', content: userInput }]);
111 |     while (true) {
112 |       const result = await this.executeSingleIteration();
113 |       onIteration?.(result);
114 |       if (!result.hasToolUse) return;
115 |     }
116 |   }
117 | }
118 | 
119 | export const agentTurn = new AgentTurn();
